import { NextRequest, NextResponse } from "next/server";
import formidable from "formidable";
import fs from "fs";
import { db } from "@/lib/db";

export const config = { api: { bodyParser: false } };

export async function POST(req: NextRequest) {
  try {
    const form = formidable({ multiples: true, keepExtensions: true });
    const [fields, files] = await new Promise((resolve, reject) => {
      form.parse(req, (err, fields, files) => {
        if (err) reject(err);
        else resolve([fields, files]);
      });
    });

    console.log("fields : ", fields);
    

    const { name, email, phone_number } = fields;
    const tenth_certificate = files.tenth_certificate?.[0]?.filepath;
    const twelfth_certificate = files.twelfth_certificate?.[0]?.filepath;

    await db.query(
      "UPDATE users SET name=?,email=?, phone_number=?, tenth_certificate=?, twelfth_certificate=? WHERE id=?",
      [name,email, phone_number, tenth_certificate, twelfth_certificate, id]
    );

    return NextResponse.json({ message: "Profile updated successfully" });
  } catch (error) {
    return NextResponse.json(
      { error: "Failed to update profile" },
      { status: 500 }
    );
  }
}
